static inline double sin_lut_lookup(uint32_t phase) {
    // phase is a full 32-bit phase accumulator; wraps naturally
    uint32_t idx = phase >> (32 - SIN_LUT_BITS);
    return sin_lut[idx & SIN_LUT_MASK];
}

static inline double cos_lut_lookup(uint32_t phase) {
    uint32_t idx = (phase >> (32 - SIN_LUT_BITS)) + (SIN_LUT_SIZE / 4);
    return sin_lut[idx & SIN_LUT_MASK];
}

static inline double sin_lut_lerp(uint32_t phase) {
    uint32_t idx  = phase >> (32 - SIN_LUT_BITS);
    uint32_t frac_bits = 32 - SIN_LUT_BITS;
    double frac = (phase & ((1u << frac_bits) - 1u)) * (1.0 / (1u << frac_bits));
    double a = sin_lut[idx & SIN_LUT_MASK];
    double b = sin_lut[(idx + 1) & SIN_LUT_MASK];
    return a + (b - a) * frac;
}

static inline double cos_lut_lerp(uint32_t phase) {
    return sin_lut_lerp(phase + (1u << (32 - 2)));
}

static inline uint32_t sin_lut_phase_from_radians(double r) {
    // Maps radians to 32-bit phase. 2*pi -> 2^32.
    const double scale = 4294967296.0 / (2.0 * 3.14159265358979323846);
    return (uint32_t)(int64_t)(r * scale);
}

